static Instruction *canonicalizeICmpBool(ICmpInst &I,
                                         InstCombiner::BuilderTy &Builder) {
  Type *OpTy = I.getOperand(0)->getType();
  // TODO: The Trunc created for scalable vectors is not simplified correctly.
  if (isa<ScalableVectorType>(OpTy))
    return nullptr;

  Value *A = I.getOperand(0), *B = I.getOperand(1);
  assert(A->getType()->isIntOrIntVectorTy(1) && "Bools only");

  // A boolean compared to true/false can be simplified to Op0/true/false in
  // 14 out of the 20 (10 predicates * 2 constants) possible combinations.
  // Cases not handled by InstSimplify are always 'not' of Op0.
  if (match(B, m_Zero())) {
    switch (I.getPredicate()) {
    case CmpInst::ICMP_EQ:  // A ==   0 -> !A
    case CmpInst::ICMP_ULE: // A <=u  0 -> !A
    case CmpInst::ICMP_SGE: // A >=s  0 -> !A
      return BinaryOperator::CreateNot(A);
    default:
      // Other cases are simplified to true/false by InstSimplify.
      return nullptr;
    }
  }

  if (match(B, m_One())) {
    switch (I.getPredicate()) {
    case CmpInst::ICMP_NE:  // A !=   1 -> !A
    case CmpInst::ICMP_ULT: // A <u   1 -> !A
    case CmpInst::ICMP_SLE: // A <=s -1 -> !A (no, A <=s 1)
      return BinaryOperator::CreateNot(A);
    default:
      // Other cases are simplified to true/false by InstSimplify.
      return nullptr;
    }
  }

  // Canonicalize icmp with bool to "icmp eq/ne %X, true".
  CmpInst::Predicate Pred = I.getPredicate();
  if (match(B, m_Zero())) {
    Pred = CmpInst::getInversePredicate(Pred);
    B = ConstantInt::getTrue(I.getContext());
    I.setOperand(1, B);
    I.setPredicate(Pred);
  }

  // We must have "icmp pred %X, true" at this point.
  assert(match(B, m_One()) && "Expected boolean comparison with true");

  // icmp eq %X, true -> trunc %X to i1
  // icmp ne %X, true -> xor (trunc %X to i1), true
  if (Pred == CmpInst::ICMP_EQ || Pred == CmpInst::ICMP_NE) {
    // This is a trunc if the input is not i1, or a no-op if it is.
    // The no-op will be folded by the InstCombiner.
    Instruction *New = CastInst::Create(Instruction::Trunc, A, I.getType());
    if (Pred == CmpInst::ICMP_NE)
      New = BinaryOperator::CreateNot(New);

    // If the cast is not a no-op, we can't be sure that the icmp is useless.
    if (New != A) {
      // Check if we can simplify the cast.
      if (Instruction *Simplified = Builder.Insert(New)) {
        if (Simplified != New) {
          New->eraseFromParent();
          New = Simplified;
        }
      }
    }

    // If we simplified the cast to a value that is not an instruction,
    // we can't replace the icmp.
    if (!isa<Instruction>(New)) {
      New->deleteValue();
      return nullptr;
    }

    // If we were not able to simplify the cast, then we can't simplify the icmp.
    if (isa<CastInst>(New)) {
      New->eraseFromParent();
      return nullptr;
    }

    // ICmp i1 X, C not simplified as expected.
    if (New == A)
      LLVM_UNREACHABLE("ICmp i1 X, C not simplified as expected.");

    return New;
  }

  // All other cases are not profitable to transform.
  return nullptr;
}
EOF
